<svg viewBox="0 0 700 650" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Texas Crypto Kiosk Fraud — Scale and Regulatory-Gap Timeline</text>
  <g font-family="sans-serif">
    <text x="20" y="60" fill="#a1a1aa" font-size="13">1. Losses, past year (est.)</text>
    <rect x="20" y="75" width="660" height="46" rx="8" fill="#f87171" opacity="0.85"/>
    <text x="350" y="103" fill="#111113" font-size="14" font-weight="700" text-anchor="middle">Texas — $56.8M (~1,200 victims)</text>
    <rect x="20" y="135" width="330" height="42" rx="8" fill="#3f3f46"/>
    <text x="185" y="161" fill="#e4e4e7" font-size="13" font-weight="700" text-anchor="middle">Florida (2nd-highest) — about half of Texas' total</text>

    <text x="20" y="205" fill="#a1a1aa" font-size="13">2. Regulatory-gap timeline</text>
    <rect x="20" y="220" width="660" height="50" rx="8" fill="#fbbf24" opacity="0.9"/>
    <text x="350" y="250" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">2025 — House and Senate each pass a kiosk-regulation bill separately</text>
    <rect x="20" y="290" width="660" height="50" rx="8" fill="#3f3f46"/>
    <text x="350" y="320" fill="#e4e4e7" font-size="13" font-weight="700" text-anchor="middle">Bills never reconciled between chambers → nothing becomes law</text>
    <rect x="20" y="360" width="660" height="50" rx="8" fill="#06b6d4" opacity="0.9"/>
    <text x="350" y="390" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Jun 2026 — East Texas lawmakers meet the state Financial Crimes Intelligence Center</text>
    <rect x="20" y="430" width="660" height="50" rx="8" fill="#f87171" opacity="0.85"/>
    <text x="350" y="460" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Next session — Rep. Hefner signals a push to ban kiosks outright</text>

    <text x="20" y="505" fill="#a1a1aa" font-size="13">3. National context</text>
